#include <bits/stdc++.h>
using namespace std;


double qbc(double xa,double ya,double xb,double yb){
    double la,lb;
    if (xa<xb){
        la=xb-xa;
    }else{
        la=xa-xb;
    }
    if (ya<yb){
        lb=yb-ya;
    }else{
        lb=ya-yb;
    }
    return sqrt(la*la+lb*lb);
}

double qmj(double bc1,double bc2,double bc3){
    double p =(bc1+bc2+bc3)/2;
    return sqrt(p*(p-bc1)*(p-bc2)*(p-bc3));
}

int main(){
    double x1,y1,x2,y2,x3,y3;
    cin>>x1>>y1>>x2>>y2>>x3>>y3;
    double bc1,bc2,bc3;
    bc1=qbc(x1,y1,x2,y2);
    bc2=qbc(x2,y2,x3,y3);
    bc3=qbc(x3,y3,x1,y1);  
    cout<<fixed<<setprecision(2)<<qmj(bc1,bc2,bc3)<<endl;
    return 0;
}
